+
+void AdapterManager::start()
+{
+  if (point_cloud_thread_flag_)
+  {
+    for (auto& iter : point_cloud_receive_adapter_vec_)
+    {
+      if (iter != nullptr)
+        iter->start();
+    }
+  }
+  if (packet_thread_flag_)
+  {
+    for (auto& iter : packet_receive_adapter_vec_)
+    {
+      if (iter != nullptr)
+      {
+        iter->start();
+      }
+    }
+  }
+}
+
+void AdapterManager::stop()
+{
+  if (point_cloud_thread_flag_)
+  {
+    for (auto& iter : point_cloud_receive_adapter_vec_)
+    {
+      if (iter != nullptr)
+        iter->stop();
+    }
+  }
+  if (packet_thread_flag_)
+  {
+    for (auto& iter : packet_receive_adapter_vec_)
+    {
+      if (iter != nullptr)
+      {
+        iter->stop();
+      }
+    }
+  }
+}
